        val trackerZ = byteArrayToBigInt(trackerZBytes) // Convert response to big integer

        // Compute challenge for tracker signature verification (Fiat-Shamir)
        val trackerE: Coll[Byte] = blake2b256(trackerABytes ++ message ++ trackerPubKey.getEncoded) // strong Fiat-Shamir
        val trackerEInt = byteArrayToBigInt(trackerE) // challenge as big integer

        // Verify tracker Schnorr signature: g^z = a * x^e
        (g.exp(trackerZ) == trackerA.multiply(trackerPubKey.exp(trackerEInt)))
      } else {
        // No tracker signature provided - only allowed after emergency period
        // Return true to allow redemption without tracker sig after emergency period
        true
      }

      // Tracker signature validation:
      // - If signature provided: must be valid (properTrackerSignature will be true/false)
      // - If no signature provided: only allowed after emergency period (enoughTimeSpent must be true)
      val trackerSigValid = if (trackerSigProvided) {
        properTrackerSignature // Must be valid if provided
      } else {
        enoughTimeSpent // Can omit sig only after emergency period
      }

      // Calculate amount being redeemed and verify it doesn't exceed debt
      val redeemed = SELF.value - selfOut.value
      val debtDelta = (totalDebt - redeemedDebt)
      // Redemption requires: valid amount + (valid tracker sig OR emergency period with no sig)
      val properlyRedeemed = (redeemed > 0) && (redeemed <= debtDelta) && trackerSigValid

      // Split reserve owner signature into components (Schnorr signature: (a, z))
      val reserveABytes = reserveSigBytes.slice(0, 33) // Random point a
      val reserveZBytes = reserveSigBytes.slice(33, reserveSigBytes.size) // Response z
      val reserveA = decodePoint(reserveABytes) // Decode random point
      val reserveZ = byteArrayToBigInt(reserveZBytes) // Convert response to big integer

      // Compute challenge for reserve signature verification (Fiat-Shamir)
      val reserveE: Coll[Byte] = blake2b256(reserveABytes ++ message ++ ownerKey.getEncoded) // strong Fiat-Shamir
      val reserveEInt = byteArrayToBigInt(reserveE) // challenge as big integer

      // Verify reserve owner Schnorr signature: g^z = a * x^e
      val properReserveSignature = (g.exp(reserveZ) == reserveA.multiply(ownerKey.exp(reserveEInt)))

      // Update the AVL tree with new timestamp and cumulative redeemed amount
      // Value format: timestamp (8 bytes) ++ newRedeemedAmount (8 bytes) = 16 bytes
      val newRedeemed = redeemedDebt + redeemed
      val treeValue = longToByteArray(timestamp) ++ longToByteArray(newRedeemed)
      val redeemedKeyVal = (key, treeValue)  // key -> (timestamp, redeemed debt value)
      val insertProof = getVar[Coll[Byte]](5).get // Merkle proof for tree insertion
      val nextTree: AvlTree = SELF.R5[AvlTree].get.insert(Coll(redeemedKeyVal), insertProof).get // todo: insertOrUpdate after appkit update
      // Verify tree was properly updated in output
      val properRedemptionTree = nextTree == selfOut.R5[AvlTree].get

      // Verify receiver's signature on transaction bytes
      val receiverCondition = proveDlog(receiver)

      // Combine all validation conditions
      sigmaProp(selfPreserved &&
                trackerIdCorrect &&
                trackerDebtCorrect &&
                timestampCorrect &&
                properRedemptionTree &&
                properReserveSignature &&
                properlyRedeemed &&
                receiverCondition)
    } else if (action == 1) {
      // top up
      sigmaProp(
        selfPreserved &&
        selfOut.R5[AvlTree].get == SELF.R5[AvlTree].get && // as R5 register preservation is not checked in selfPreserved
        (selfOut.value - SELF.value >= 100000000) // at least 0.1 ERG added
      )
    } else {
      sigmaProp(false)
    }

}

{
    // Contract for reserve (in ERG only)

    // Data:
    //  - token #0 - identifying singleton token
    //  - R4 - signing key (as a group element)
    //  - R5 - tree of all the note tokens issued TODO: check preservation in actions
    //
    // Actions:
    //  - redeem note (#0)
    //  - top up      (#1)
    //  - mint note (#2)

    val v = getVar[Byte](0).get
    val action = v / 10
    val index = v % 10

    val ownerKey = SELF.R4[GroupElement].get // reserve owner's key, used in notes and unlock/lock/refund actions
    val selfOut = OUTPUTS(index)

    // common checks for all the paths (not incl. ERG value check)
    val selfPreserved =
            selfOut.propositionBytes == SELF.propositionBytes &&
            selfOut.tokens == SELF.tokens &&
            selfOut.R4[GroupElement].get == SELF.R4[GroupElement].get

    if (action == 0) {
      // redemption path

      // OUTPUTS:
      // #1 - receipt
      // #2 - buyback

      val g: GroupElement = groupGenerator

      // if set, re-redemption against receipt data is done, otherwise, a note is redeemed
      val receiptMode = getVar[Boolean](4).get

      // read note data if receiptMode == false, receipt data otherwise
      val noteInput = INPUTS(index)
      val noteTokenId = noteInput.tokens(0)._1
      val noteValue = noteInput.tokens(0)._2 // 1 token == 1 mg of gold
      val history = noteInput.R4[AvlTree].get
      val reserveId = SELF.tokens(0)._1

      // oracle provides gold price in nanoErg per kg in its R4 register
      val goldOracle = CONTEXT.dataInputs(0)
      // todo: externalize oracle NFT id
      // the ID below is from the mainnet
      val properOracle = goldOracle.tokens(0)._1 == fromBase16("3c45f29a5165b030fdb5eaf5d81f8108f9d8f507b31487dd51f4ae08fe07cf4a")
      val oracleRate = goldOracle.R4[Long].get / 1000000 // normalize to nanoerg per mg of gold

      // 2% redemption fee
      val maxToRedeem = noteValue * oracleRate * 98 / 100
      val redeemed = SELF.value - selfOut.value

      // 0.2% going to buyback contract to support oracles network
      val buyBackCorrect = if (redeemed > 0) {
        val toOracle = redeemed * 2 / 1000
        // todo: externalize buyback NFT id
        // the ID below is from the mainnet
        val buyBackNFTId = fromBase16("bf24ed4af7eb5a7839c43aa6b240697d81b196120c837e1a941832c266d3755c")
        val buyBackInput = INPUTS(2)
        val buyBackOutput = OUTPUTS(2)

        buyBackInput.tokens(0)._1 == buyBackNFTId &&
            buyBackOutput.tokens(0)._1 == buyBackNFTId &&
            (buyBackOutput.value - buyBackInput.value) >= toOracle
      } else {
        true
      }
      val redeemCorrect = (redeemed <= maxToRedeem) && buyBackCorrect

      val position = getVar[Long](3).get
      val positionBytes = longToByteArray(position)

      val proof = getVar[Coll[Byte]](1).get
      val key = positionBytes ++ reserveId
      val value = history.get(key, proof).get

      val aBytes = value.slice(0, 33)
      val zBytes = value.slice(33, value.size)
      val a = decodePoint(aBytes)
      val z = byteArrayToBigInt(zBytes)

      val maxValueBytes = getVar[Coll[Byte]](2).get

      val message = positionBytes ++ maxValueBytes ++ noteTokenId
      val maxValue = byteArrayToLong(maxValueBytes)

      // Computing challenge
      val e: Coll[Byte] = blake2b256(aBytes ++ message ++ ownerKey.getEncoded) // strong Fiat-Shamir
      val eInt = byteArrayToBigInt(e) // challenge as big integer

      // Signature is valid if g^z = a * x^e
      val properSignature = (g.exp(z) == a.multiply(ownerKey.exp(eInt))) &&
                             noteValue <= maxValue

      // we check that receipt is properly formed, but we do not check receipt's contract here,
      // to avoid circular dependency as receipt contract depends on (hash of) our contract,
      // thus we are checking receipt contract in note and receipt contracts
      val receiptOutIndex = if (redeemed == 0) {
         getVar[Int](5).get
      } else {
         1
      }
      val receiptOut = OUTPUTS(receiptOutIndex)
      val properReceipt =
        receiptOut.tokens(0) == noteInput.tokens(0) &&
        receiptOut.R4[AvlTree].get == history  &&
        receiptOut.R5[Long].get == position    &&
        receiptOut.R6[Int].get >= HEIGHT - 20  &&  // 20 blocks for inclusion
        receiptOut.R6[Int].get <= HEIGHT &&
        receiptOut.R7[GroupElement].get == ownerKey

      // todo: could this be checked all the time ? if so then receiptMode can be eliminated
      val positionCorrect = if (receiptMode) {
        position < noteInput.R5[Long].get
      } else {
        true
      }

      sigmaProp(selfPreserved && properOracle && redeemCorrect && properSignature && properReceipt && positionCorrect)
    } else if (action == 1) {
      // top up
      // todo: check R5 preservation
      sigmaProp(selfPreserved && (selfOut.value - SELF.value >= 1000000000)) // at least 1 ERG added
    } else if (action == 2) {
      // issue a note
      // todo: check R5 preservation
      sigmaProp(selfPreserved)
    } else {
      sigmaProp(false)
    }

}

